function runeCostForLevel(l){if(l<=1||l>713)return 0;var n=l+80;var x100=Math.max(0,(l-12)*2);return Math.floor(((x100+10)*n*n+100)/100);}

function levelsFromRunes(fromLevel,runes){var l=fromLevel,budget=runes;while(budget>=runeCostForLevel(l+1)){budget-=runeCostForLevel(l+1);l++;}return l-fromLevel;}

function totalRunesForLevels(from,to){var t=0;for(var l=from+1;l<=to;l++)t+=runeCostForLevel(l);return t;}

