function engEquip(e){var t=ENG_DATA.derivedStats.equipLoad.values;var keys=_dsKeys.equip;if(e<=keys[0])return t[keys[0]];if(e>=keys[keys.length-1])return t[keys[keys.length-1]];for(var i=0;i<keys.length-1;i++){if(e>=keys[i]&&e<=keys[i+1]){var r=(e-keys[i])/(keys[i+1]-keys[i]);return Math.round((t[keys[i]]+(t[keys[i+1]]-t[keys[i]])*r)*10)/10;}}return t[keys[keys.length-1]];}

