function engDefenseMult(ratio){
  if(ratio<0.125)return 0.10;
  if(ratio<1.0)return 0.10+Math.pow(ratio-0.125,2)/2.552;
  if(ratio<2.5)return 0.70-Math.pow(2.5-ratio,2)/7.5;
  if(ratio<8.0)return 0.90-Math.pow(8.0-ratio,2)/151.25;
  return 0.90;
}

function engDmgVsBoss(arResult,boss,weaponType){
  var ph=boss.ph[0];
  var physNeg=PHYS_SUBTYPE[weaponType]||"standard";
  var negMap={0:physNeg,1:"magic",2:"fire",3:"lightning",4:"holy"};
  var total=0,bd={};
  [0,1,2,3,4].forEach(function(dt){
    var ar=arResult.attackPower[dt]||0;if(ar<=0)return;
    // Stage 1: Defense — piecewise non-linear curve on raw AR
    var def=ph.df||100;
    var afterDef=ar*engDefenseMult(ar/def);
    // Stage 2: Negation — percentage reduction using correct physical subtype
    var neg=ph.ng[negMap[dt]]||0;
    var dmg=afterDef*(1-neg/100);
    bd[ENG_DMG_NAMES[dt]]=Math.floor(dmg);total+=dmg;
  });
  return{total:Math.floor(total),breakdown:bd,hitsToKill:Math.ceil((boss.hp||1)/Math.max(total,1))};
}

function engSpellDmgVsBoss(spellScaling,spell,boss){
  var sd=SPELL_DMG[spell.name];if(!sd)return null;
  var rawDmg=spellScaling*sd.dmg;
  // Apply boss magic/fire/lightning/holy negation based on spell type
  var ph=boss.ph[0];var negType=spell.type==="Fire"?"fire":spell.type==="Lightning"?"lightning":spell.type==="Holy"?"holy":spell.type==="Physical"?"standard":"magic";
  var neg=ph.ng[negType]||0;
  // Apply defense curve (same as melee, using boss defense)
  var def=ph.df||100;
  var afterDef=rawDmg*engDefenseMult(rawDmg/def);
  var dmg=Math.floor(afterDef*(1-neg/100));
  var dps=sd.castTime>0?Math.floor(dmg/sd.castTime):dmg;
  var fpPerDmg=dmg>0?(spell.fp/dmg):999;
  return{damage:dmg,dps:dps,fp:spell.fp,fpEfficiency:Math.round(fpPerDmg*1000)/1000,castTime:sd.castTime,notes:sd.notes||""};
}

function engStatusVsBoss(arResult,boss){
  var ph=boss.ph[0];var rs=ph.rs||{};var results=[];
  Object.keys(STATUS_TYPES).forEach(function(dtKey){
    var dt=parseInt(dtKey);var statusName=STATUS_TYPES[dt];
    var buildup=arResult.attackPower[dt]||0;
    if(!buildup||buildup<1)return;
    var threshold=rs[statusName];
    if(!threshold||threshold==="IMMUNE")return;
    var hitsToProcBase=Math.ceil(threshold/buildup);
    var hitsToProc=Math.ceil(hitsToProcBase*1.3);
    var procDmg=Math.floor(STATUS_PROC_DAMAGE[statusName]*boss.hp);
    results.push({status:statusName,label:STATUS_NAMES[statusName],color:STATUS_COLORS[statusName],
      buildup:Math.floor(buildup),threshold:threshold,hitsToProc:hitsToProc,
      procDamage:procDmg,procsToKill:procDmg>0?Math.ceil(boss.hp/procDmg):999});
  });
  return results;
}

function getBossPoiseInfo(boss){
  var ph=boss.ph[0];if(!ph||!ph.po)return null;
  var poise=ph.po;
  var difficulty=poise<=40?"Easy to stagger":poise<=80?"Moderate poise":poise<=120?"High poise":"Very high poise — colossal weapons recommended";
  return{poise:poise,difficulty:difficulty};
}

function availableSpells(stats,type,step){
  var list=type==="sorcery"?ENG_DATA.sorceries:ENG_DATA.incantations;
  if(!list)return[];
  return list.filter(function(s){
    if(!Object.keys(s.req).every(function(k){return(stats[k]||0)>=s.req[k];}))return false;
    if(step!==undefined&&SPELL_STEP[s.name]!==undefined&&SPELL_STEP[s.name]>step)return false;
    return true;
  });
}

function availableBuffs(template,stats,step){
  return WEAPON_BUFFS.filter(function(b){
    if(b.step>step)return false;
    return Object.keys(b.req).every(function(k){return(stats[k]||0)>=b.req[k];});
  });
}

function bestAshOfWar(template,step){
  var pri=template.primaryStats||[];
  return ASHES_OF_WAR.filter(function(a){
    if(a.step>step)return false;
    if(a.type==="Physical"&&(pri.indexOf("str")>=0||pri.indexOf("dex")>=0))return true;
    if(a.type==="Magic"&&pri.indexOf("int")>=0)return true;
    if(a.type==="Fire"&&pri.indexOf("fai")>=0)return true;
    if(a.type==="Buff"||a.type==="Movement")return true;
    // Universal picks
    if(a.tier==="spam"&&a.type==="Physical")return true;
    return false;
  }).sort(function(a,b){return b.dmgMult-a.dmgMult;}).slice(0,5);
}

function computeTalismanBonus(templateId){
  var loadout=TALISMAN_LOADOUT[templateId];
  if(!loadout)return{statBonus:{},meleeMult:1,spellMult:1};
  var sb={},mm=1,sm=1;
  loadout.forEach(function(t){
    // Stat bonuses — added to effective stats before AR calc
    if(t.statBonus){Object.keys(t.statBonus).forEach(function(k){sb[k]=(sb[k]||0)+t.statBonus[k];});}
    // Damage multipliers — categorize by application
    if(!t.dmgMult)return;
    if(t.dmgType==="all"){mm*=(1+t.dmgMult);sm*=(1+t.dmgMult);}
    else if(t.dmgType==="spell"){sm*=(1+t.dmgMult);}
    else if(t.dmgType==="skill"||t.dmgType==="jump"||t.dmgType==="charged"){
      // These are attack-type conditional — apply as average uplift (~40% of attacks)
      mm*=(1+t.dmgMult*0.4);
    }
    else if(typeof t.dmgType==="number"){
      // Element-specific (0-4) — applies to that damage type's share.
      // For simplicity, treat as full bonus since archetype weapons match element.
      mm*=(1+t.dmgMult);sm*=(1+t.dmgMult);
    }
  });
  return{statBonus:sb,meleeMult:Math.round(mm*1000)/1000,spellMult:Math.round(sm*1000)/1000};
}

function meetsRequirements(wEnc,stats,twoHand){
  var r=wEnc.r;if(!r)return true;
  var effStr=twoHand&&!wEnc.p?Math.floor(stats.str*1.5):stats.str;
  if(twoHand&&[50,51,53,56].indexOf(wEnc.t)>=0)effStr=Math.floor(stats.str*1.5);
  if(r.str&&effStr<r.str)return false;if(r.dex&&stats.dex<r.dex)return false;
  if(r.int&&stats.int<r.int)return false;if(r.fai&&stats.fai<r.fai)return false;
  if(r.arc&&stats.arc<r.arc)return false;return true;
}

function globalOptimize(targetLevel,includeDLC,options,weaponList){
  var riskMode=(options&&options.riskMode)||'total';
  var bossList=MANDATORY_BOSSES.base.slice();
  if(includeDLC)bossList=bossList.concat(MANDATORY_BOSSES.dlc);
  var bossCount=bossList.length;
  // Resolve boss objects once
  var bossObjs=[];
  for(var bi=0;bi<bossCount;bi++){
    var bo=ENG_DATA.bosses[bossList[bi].idx];
    if(bo)bossObjs.push({entry:bossList[bi],boss:bo});
  }
  var resolvedBossCount=bossObjs.length;
  var allWeapons=weaponList||ENG_DATA.reg.w;
  var results=[];

  // DD37: Wretch only — eliminates 9/10 class iterations
  var cls=WRETCH;
  STAT_TEMPLATES.forEach(function(template){
      var stats=resolveStats(cls,template,targetLevel);

      // Phase 1: Filter eligible weapons + decode + compute AR (both grips)
      var wpns=[]; // {name, affinityId, ar1H, ar2H}
      for(var wi=0;wi<allWeapons.length;wi++){
        var wEnc=allWeapons[wi];
        var m1H=meetsRequirements(wEnc,stats,false);
        var m2H=meetsRequirements(wEnc,stats,true);
        if(!m1H&&!m2H)continue;
        var maxLvl=(ENG_DATA.reg.rt[wEnc.ri]||[]).length-1;
        var dec=engDecodeWAtLevel(wEnc,maxLvl);
        if(!dec)continue;
        wpns.push({
          name:wEnc.w,
          affinityId:wEnc.a,
          wType:wEnc.t,
          ar1H:m1H?engCalcAR(dec,stats,0,false):null,
          ar2H:m2H?engCalcAR(dec,stats,0,true):null
        });
      }
      if(wpns.length===0)return;

      var wCount=wpns.length;
      // Per-weapon accumulators for single-weapon scoring
      var wTotalHTK=new Array(wCount);
      var wWorstHTK=new Array(wCount);
      var wWorstBossName=new Array(wCount);
      for(var i=0;i<wCount;i++){wTotalHTK[i]=0;wWorstHTK[i]=0;wWorstBossName[i]='';}

      // Portfolio: best weapon per boss
      var portBosses=new Array(resolvedBossCount);

      for(var bi=0;bi<resolvedBossCount;bi++){
        var bObj=bossObjs[bi];
        var boss=bObj.boss;
        var bHP=boss.hp||1;
        var bestDmg=0,bestHTK=999999,bestWI=-1,bestGrip='1H';

        for(var wi=0;wi<wCount;wi++){
          var w=wpns[wi];
          var dmg=0,grip='1H';
          if(w.ar1H){dmg=engDmgVsBoss(w.ar1H,boss,w.wType).total;}
          if(w.ar2H){var d2=engDmgVsBoss(w.ar2H,boss,w.wType).total;if(d2>dmg){dmg=d2;grip='2H';}}
          var htk=Math.ceil(bHP/Math.max(dmg,1));
          wTotalHTK[wi]+=htk;
          if(htk>wWorstHTK[wi]){wWorstHTK[wi]=htk;wWorstBossName[wi]=bObj.entry.name;}
          if(dmg>bestDmg){bestDmg=dmg;bestHTK=htk;bestWI=wi;bestGrip=grip;}
        }
        portBosses[bi]={
          boss:bObj.entry.name,
          weapon:bestWI>=0?wpns[bestWI].name:'None',
          affinity:bestWI>=0?(ENG_AFFINITY_NAMES[wpns[bestWI].affinityId]||'Unknown'):'',
          grip:bestGrip,dmg:bestDmg,htk:bestHTK
        };
      }

      // Find best single weapon (lowest total HTK across roster)
      var bestSI=0;
      for(var wi=1;wi<wCount;wi++){if(wTotalHTK[wi]<wTotalHTK[bestSI])bestSI=wi;}

      var portTotalHTK=0;
      for(var bi=0;bi<resolvedBossCount;bi++)portTotalHTK+=portBosses[bi].htk;

      // Vulnerability report: recompute single weapon's per-boss HTK
      var sw=wpns[bestSI];
      var vulns=[];
      for(var bi=0;bi<resolvedBossCount;bi++){
        var bObj=bossObjs[bi];var boss=bObj.boss;var bHP=boss.hp||1;
        var dmg=0,grip='1H';
        if(sw.ar1H){dmg=engDmgVsBoss(sw.ar1H,boss,sw.wType).total;}
        if(sw.ar2H){var d2=engDmgVsBoss(sw.ar2H,boss,sw.wType).total;if(d2>dmg){dmg=d2;grip='2H';}}
        var sHTK=Math.ceil(bHP/Math.max(dmg,1));
        var pHTK=portBosses[bi].htk;
        if(pHTK>0&&(sHTK-pHTK)/pHTK>=0.20){
          vulns.push({boss:bObj.entry.name,singleHTK:sHTK,portfolioHTK:pHTK,
            betterWeapon:portBosses[bi].weapon,affinity:portBosses[bi].affinity,grip:portBosses[bi].grip});
        }
      }

      results.push({
        className:"Wretch",classId:"wretch",
        templateName:template.name,templateId:template.id,
        stats:stats,
        singleWeapon:{name:sw.name,affinity:ENG_AFFINITY_NAMES[sw.affinityId]||'Unknown',
          totalHTK:wTotalHTK[bestSI],
          worstBoss:{name:wWorstBossName[bestSI],htk:wWorstHTK[bestSI]}},
        portfolio:{totalHTK:portTotalHTK,weapons:portBosses},
        gap:wTotalHTK[bestSI]-portTotalHTK,
        vulnerabilities:vulns
      });
  });

  // Phase 2: Rank
  if(riskMode==='maximin'){
    results.sort(function(a,b){return a.singleWeapon.worstBoss.htk-b.singleWeapon.worstBoss.htk;});
  }else{
    results.sort(function(a,b){return a.singleWeapon.totalHTK-b.singleWeapon.totalHTK;});
  }
  return results.slice(0,10);
}

function bestWeaponForBoss(bossName,stats,gateState,regionName,twoHand,weaponList){
  var bossIdx=BOSS_ENG_MAP[bossName];
  if(bossIdx===undefined)return[];
  var boss=ENG_DATA.bosses[bossIdx];if(!boss)return[];
  var rc=REGION_CAPS[regionName]||{reg:0,smbr:0};
  var maxReg=Math.max(rc.reg,gateState.buyableRegMax);
  var maxSom=Math.max(rc.smbr,gateState.buyableSomMax);
  var affIds=gateState.affinities;
  var engStats={str:stats.str||10,dex:stats.dex||10,int:stats.int||10,fai:stats.fai||10,arc:stats.arc||10};
  var results=[];
  (weaponList||ENG_DATA.reg.w).forEach(function(wEnc){
    if(wEnc.a!==-1&&affIds.indexOf(wEnc.a)===-1)return;
    if(!meetsRequirements(wEnc,engStats,twoHand))return; // Pre-filter before decode
    var maxUp=(ENG_DATA.reg.rt[wEnc.ri]||[]).length-1;
    var upg=Math.min((wEnc.a===-1)?maxSom:maxReg,maxUp);
    var decoded=engDecodeWAtLevel(wEnc,upg);if(!decoded)return; // Single-level decode
    var ar=engCalcAR(decoded,engStats,0,twoHand);
    var dmg=engDmgVsBoss(ar,boss,wEnc.t);
    var statusEffects=engStatusVsBoss(ar,boss);
    var statusDPS=0;statusEffects.forEach(function(se){if(se.procDamage>0)statusDPS+=se.procDamage/se.hitsToProc;});
    var effectiveDmg=dmg.total+statusDPS;
    var totalAR=0;[0,1,2,3,4].forEach(function(dt){totalAR+=(ar.attackPower[dt]||0);});
    var effectiveHTK=Math.ceil((boss.hp||1)/Math.max(effectiveDmg,1));
    results.push({name:wEnc.w,affinity:wEnc.a,affinityName:ENG_AFFINITY_NAMES[wEnc.a]||"Unique",upgrade:upg,totalAR:Math.floor(totalAR),dmgPerHit:Math.floor(effectiveDmg),meleeDmg:dmg.total,hitsToKill:effectiveHTK,statusEffects:statusEffects,statusDPS:Math.floor(statusDPS),breakdown:dmg.breakdown});
  });
  results.sort(function(a,b){return b.dmgPerHit-a.dmgPerHit;});
  return results.slice(0,10);
}

function computeStatCostToEquip(wEnc,stats,twoHand){
  var r=wEnc.r;if(!r)return{levels:0,gaps:{}};
  var gaps={};var total=0;
  if(r.str){
    var effStr=twoHand?Math.floor(stats.str*1.5):stats.str;
    if(effStr<r.str){
      var need=twoHand?Math.ceil(r.str/1.5):r.str;
      var gap=Math.max(need-stats.str,0);
      if(gap>0){gaps.str=gap;total+=gap;}
    }
  }
  ["dex","int","fai","arc"].forEach(function(s){
    if(r[s]&&stats[s]<r[s]){var gap=r[s]-stats[s];gaps[s]=gap;total+=gap;}
  });
  return{levels:total,gaps:gaps};
}

function vigFloorForBoss(bossLevel){
  if(bossLevel<=25)return 15;if(bossLevel<=50)return Math.round(15+(bossLevel-25)*0.4);
  if(bossLevel<=80)return Math.round(25+(bossLevel-50)*0.33);
  if(bossLevel<=120)return Math.round(35+(bossLevel-80)*0.125);return 40;
}

function optimizeStats(params){
  var boss=ENG_DATA.bosses[params.bossIdx];if(!boss)return null;
  var presets={aggressive:{survWeight:50,sustWeight:15},balanced:{survWeight:75,sustWeight:25},tanky:{survWeight:100,sustWeight:35}};
  var w=presets[params.preset]||presets.balanced;
  var cls=params.cls||WRETCH;
  var stats={};["vig","mnd","end","str","dex","int","fai","arc"].forEach(function(s){stats[s]=cls[s];});
  var free=params.targetLevel-cls.level;
  if(free<=0)return{stats:stats,score:0,hp:engHP(stats.vig),fp:engFP(stats.mnd),stamina:engStam(stats.end),dmgPerHit:0,hitsToKill:999,weapon:params.wEnc.w,upgrade:0,bossName:boss.ph[0].n};
  // Decode weapon
  var rc=REGION_CAPS[params.region]||{reg:0,smbr:0};
  var maxUp=(ENG_DATA.reg.rt[params.wEnc.ri]||[]).length-1;
  var gsBuyReg=params.gateState?params.gateState.buyableRegMax:0;
  var gsBuySom=params.gateState?params.gateState.buyableSomMax:0;
  var upg=Math.min(params.wEnc.a===-1?Math.max(rc.smbr,gsBuySom):Math.max(rc.reg,gsBuyReg),maxUp);
  var decoded=engDecodeWAtLevel(params.wEnc,upg);if(!decoded)return null;
  // Decode catalyst for casters
  var catalystDec=null;
  if(params.catalystEnc){
    var catMaxUp=(ENG_DATA.reg.rt[params.catalystEnc.ri]||[]).length-1;
    var catUpg=Math.min(Math.max(rc.smbr,gsBuySom),catMaxUp);
    catalystDec=engDecodeWAtLevel(params.catalystEnc,catUpg);
  }
  // Phase 1: Hard constraints — weapon reqs + survivability floors
  var engStats={str:stats.str,dex:stats.dex,int:stats.int,fai:stats.fai,arc:stats.arc};
  var reqCost=computeStatCostToEquip(params.wEnc,engStats,params.twoHand);
  Object.keys(reqCost.gaps).forEach(function(s){stats[s]+=reqCost.gaps[s];free-=reqCost.gaps[s];});
  var bossLvl=boss.hp?params.targetLevel:25;
  // Use MANDATORY_BOSSES to find boss level if available
  MANDATORY_BOSSES.base.concat(MANDATORY_BOSSES.dlc||[]).forEach(function(mb){if(mb.idx===params.bossIdx)bossLvl=mb.lvl;});
  var vigMin=vigFloorForBoss(bossLvl);
  var mndMin=params.isCaster?mndFloorForCaster(bossLvl):10;
  var endMin=endFloor();
  [{s:"vig",f:vigMin},{s:"mnd",f:mndMin},{s:"end",f:endMin}].forEach(function(c){
    var need=Math.max(c.f-stats[c.s],0);
    if(need>0&&free>=need){stats[c.s]+=need;free-=need;}
  });
  // Phase 2: Greedy marginal allocation
  var scoreParams=Object.assign({},w,{twoHand:params.twoHand,isCaster:params.isCaster,catalystDec:catalystDec,spell:params.spell});
  var allStats=["vig","mnd","end","str","dex","int","fai","arc"];
  while(free>0){
    var bestStat=null,bestGain=-Infinity;
    var baseScore=scoreAllocation(stats,decoded,boss,params.wEnc.t,scoreParams);
    for(var si=0;si<allStats.length;si++){
      var s=allStats[si];if(stats[s]>=99)continue;
      stats[s]++;
      var gain=scoreAllocation(stats,decoded,boss,params.wEnc.t,scoreParams)-baseScore;
      if(gain>bestGain){bestGain=gain;bestStat=s;}
      stats[s]--;
    }
    if(!bestStat)break;
    stats[bestStat]++;free--;
  }
  // Final metrics
  var fAR=engCalcAR(decoded,{str:stats.str,dex:stats.dex,int:stats.int,fai:stats.fai,arc:stats.arc},0,params.twoHand);
  var fDmg=engDmgVsBoss(fAR,boss,params.wEnc.t);
  var fStat=engStatusVsBoss(fAR,boss);
  var fSDPS=0;fStat.forEach(function(se){if(se.procDamage>0)fSDPS+=se.procDamage/se.hitsToProc;});
  return{stats:stats,level:params.targetLevel,preset:params.preset,
    hp:engHP(stats.vig),fp:engFP(stats.mnd),stamina:engStam(stats.end),
    dmgPerHit:Math.floor(fDmg.total+fSDPS),meleeDmg:Math.floor(fDmg.total),statusDPS:Math.floor(fSDPS),
    hitsToKill:Math.ceil(boss.hp/Math.max(fDmg.total+fSDPS,1)),
    weapon:params.wEnc.w,affinityName:ENG_AFFINITY_NAMES[params.wEnc.a]||"Unique",upgrade:upg,
    twoHand:params.twoHand,bossName:boss.ph[0].n,bossHP:boss.hp};
}

function computeWeaponValue(wEnc,stats,gateState,target,twoHand){
  var rc=REGION_CAPS[target.region||target.rg]||{reg:0,smbr:0};
  var maxReg=Math.max(rc.reg,gateState.buyableRegMax);
  var maxSom=Math.max(rc.smbr,gateState.buyableSomMax);
  var maxUp=(ENG_DATA.reg.rt[wEnc.ri]||[]).length-1;
  var upg=Math.min(wEnc.a===-1?maxSom:maxReg,maxUp);
  var decoded=engDecodeWAtLevel(wEnc,upg);if(!decoded)return null;
  var engStats={str:stats.str||10,dex:stats.dex||10,int:stats.int||10,fai:stats.fai||10,arc:stats.arc||10};
  var ar=engCalcAR(decoded,engStats,0,twoHand);
  if(target.ph){
    var dmg=engDmgVsBoss(ar,target,wEnc.t);
    var status=engStatusVsBoss(ar,target);
    var statusDPS=0;status.forEach(function(se){if(se.procDamage>0)statusDPS+=se.procDamage/se.hitsToProc;});
    return{weapon:wEnc.w,affinity:wEnc.a,affinityName:ENG_AFFINITY_NAMES[wEnc.a]||"Unique",
      upgrade:upg,twoHand:twoHand,weaponType:wEnc.t,
      dmgPerHit:Math.floor(dmg.total+statusDPS),meleeDmg:dmg.total,
      hitsToKill:Math.ceil((target.hp||1)/Math.max(dmg.total+statusDPS,1)),
      statusEffects:status,statusDPS:Math.floor(statusDPS),
      arTotal:Object.values(ar.attackPower).reduce(function(s,v){return s+(v||0);},0)};
  }
  // Farm targets without boss phase data — evaluate by AR and type match
  var arTotal=Object.values(ar.attackPower).reduce(function(s,v){return s+(v||0);},0);
  var physSub=PHYS_SUBTYPE[wEnc.t]||"standard";
  // For bleed farm targets, compute proc info
  var bleedBuildup=0;
  [5,6,7,8,9,10].forEach(function(dt){var b=ar.attackPower[dt]||0;if(STATUS_TYPES[dt]==="bleed"&&b>0)bleedBuildup=b;});
  return{weapon:wEnc.w,affinity:wEnc.a,affinityName:ENG_AFFINITY_NAMES[wEnc.a]||"Unique",
    upgrade:upg,twoHand:twoHand,weaponType:wEnc.t,physSub:physSub,
    arTotal:Math.floor(arTotal),bleedBuildup:Math.floor(bleedBuildup)};
}

function evaluateChoices(charData,ci,includeDLC){
  if(!charData)charData={};
  var stats=charData.stats||{vig:10,mnd:10,end:10,str:10,dex:10,int:10,fai:10,arc:10};
  var engStats={str:stats.str||10,dex:stats.dex||10,int:stats.int||10,fai:stats.fai||10,arc:stats.arc||10};
  var step=deriveCurrentStep(ci);
  var gateState=deriveGateState(ci);
  var nextBoss=getNextMandatoryBoss(ci,includeDLC);
  var template=charData.archetype?STAT_TEMPLATES.find(function(t){return t.id===charData.archetype}):null;
  var level=computeLevel(stats);
  var actions=[];

  // --- NEAR-MISS WEAPONS ---
  var pool=ENG_DATA.reg.w;
  if(template)pool=filterArchPool(pool,template.affPref||[],template.primaryStats||[],true);
  var seen={};
  pool.forEach(function(wEnc){
    if(wEnc.a!==-1&&gateState.affinities.indexOf(wEnc.a)===-1)return;
    if(WEAPON_STEPS[wEnc.w]!==undefined&&WEAPON_STEPS[wEnc.w]>step)return;
    if(meetsRequirements(wEnc,engStats,false)||meetsRequirements(wEnc,engStats,true))return;
    var key=wEnc.w+"|"+wEnc.a;if(seen[key])return;seen[key]=true;

    var cost1h=computeStatCostToEquip(wEnc,engStats,false);
    var cost2h=computeStatCostToEquip(wEnc,engStats,true);
    var best=cost2h.levels<cost1h.levels?cost2h:cost1h;
    var grip=best===cost2h;

    if(best.levels>0&&best.levels<=10){
      var hypoStats=Object.assign({},engStats);
      Object.keys(best.gaps).forEach(function(s){hypoStats[s]+=best.gaps[s];});
      var value=null;
      if(nextBoss&&nextBoss.engBoss){
        value=computeWeaponValue(wEnc,hypoStats,gateState,nextBoss.engBoss,grip);
      }
      actions.push({type:"near_miss_weapon",weapon:wEnc.w,
        affinity:ENG_AFFINITY_NAMES[wEnc.a]||"Unique",weaponType:wEnc.t,
        cost:best,twoHand:grip,value:value,
        physSub:PHYS_SUBTYPE[wEnc.t]||"standard",
        hasBleed:weaponMatchesFarmMethod(wEnc,{method:"bleed"})});
    }
  });

  // --- FARM TARGETS ---
  FARM_TARGETS.forEach(function(ft){
    // Find best available weapon for this farm method
    var bestFarmWeapon=null;var bestFarmNearMiss=null;
    ENG_DATA.reg.w.forEach(function(wEnc){
      if(!weaponMatchesFarmMethod(wEnc,ft))return;
      if(WEAPON_STEPS[wEnc.w]!==undefined&&WEAPON_STEPS[wEnc.w]>step)return;
      if(wEnc.a!==-1&&gateState.affinities.indexOf(wEnc.a)===-1)return;
      if(meetsRequirements(wEnc,engStats,false)||meetsRequirements(wEnc,engStats,true)){
        var val=computeWeaponValue(wEnc,engStats,gateState,
          ft.ph?ft:{region:ft.region,ph:null,hp:ft.hp||1},
          meetsRequirements(wEnc,engStats,true));
        if(val&&(!bestFarmWeapon||val.arTotal>bestFarmWeapon.arTotal))bestFarmWeapon=val;
      }else{
        var c1=computeStatCostToEquip(wEnc,engStats,false);
        var c2=computeStatCostToEquip(wEnc,engStats,true);
        var bc=c2.levels<c1.levels?c2:c1;
        if(bc.levels<=5&&(!bestFarmNearMiss||bc.levels<bestFarmNearMiss.cost.levels)){
          bestFarmNearMiss={weapon:wEnc.w,cost:bc,twoHand:bc===c2,weaponType:wEnc.t};
        }
      }
    });
    // Compute Greyoll-specific bleed info
    var bleedInfo=null;
    if(ft.method==="bleed"&&ft.hp&&ft.bleedThreshold&&bestFarmWeapon&&bestFarmWeapon.bleedBuildup>0){
      var hitsPerProc=Math.ceil(Math.ceil(ft.bleedThreshold/bestFarmWeapon.bleedBuildup)*1.3);
      var procDmg=Math.floor(ft.hp*0.15);
      var procsToKill=Math.ceil(ft.hp/procDmg);
      var totalHits=hitsPerProc*procsToKill;
      bleedInfo={hitsPerProc:hitsPerProc,procDmg:procDmg,procsToKill:procsToKill,totalHits:totalHits,
        buildup:bestFarmWeapon.bleedBuildup};
    }
    // Compute levels gained from rune reward
    var levelsGained=ft.reward.runes?levelsFromRunes(level,ft.reward.runes):0;
    actions.push({type:"farm_target",target:ft,
      hasWeapon:!!bestFarmWeapon,bestWeapon:bestFarmWeapon,
      nearMissWeapon:bestFarmNearMiss,bleedInfo:bleedInfo,
      levelsGained:levelsGained,reachable:ft.step<=step+500});
  });

  // --- GATE UNLOCKS ---
  if(gateState.nextWhet){
    actions.push({type:"gate_unlock",subtype:"whetstone",
      gate:gateState.nextWhet,step:gateState.nextWhet.step,
      unlocks:gateState.nextWhet.labels.join(", ")});
  }
  if(gateState.nextRegBB){
    actions.push({type:"gate_unlock",subtype:"bell_bearing_reg",
      gate:gateState.nextRegBB,step:gateState.nextRegBB.step,
      unlocks:"infinite Stone ["+gateState.nextRegBB.unlocks.join(",")+"]"});
  }
  if(gateState.nextSomBB){
    actions.push({type:"gate_unlock",subtype:"bell_bearing_som",
      gate:gateState.nextSomBB,step:gateState.nextSomBB.step,
      unlocks:"infinite Somber ["+gateState.nextSomBB.unlocks.join(",")+"]"});
  }

  // --- RANK ---
  return rankActions(actions,nextBoss,engStats,level,gateState);
}

function rankActions(actions,nextBoss,stats,level,gateState){
  var baselineHTK=999;
  if(nextBoss&&nextBoss.engBoss){
    var r2h=bestWeaponForBoss(nextBoss.name,stats,gateState,nextBoss.region,true);
    var r1h=bestWeaponForBoss(nextBoss.name,stats,gateState,nextBoss.region,false);
    var cur=r2h[0]||r1h[0]||null;
    if(cur)baselineHTK=cur.hitsToKill;
  }
  actions.forEach(function(a){
    var score=0;
    switch(a.type){
      case"near_miss_weapon":
        if(a.value&&a.value.hitsToKill){
          var delta=baselineHTK-a.value.hitsToKill;
          score=Math.max(delta,0)/Math.max(a.cost.levels,1);
          if(a.value.statusDPS>0)score*=1.2;
          if(a.hasBleed)score*=1.1;
        }
        break;
      case"farm_target":
        if(a.target.type==="runes"&&a.levelsGained>0){
          score=a.levelsGained*2;
          if(!a.hasWeapon&&!a.nearMissWeapon)score=0;
        }
        if(a.target.type==="materials"){
          score=a.hasWeapon?5:a.nearMissWeapon?3:0;
        }
        if(!a.reachable)score*=0.3;
        break;
      case"gate_unlock":
        score=a.subtype==="bell_bearing_reg"?8:a.subtype==="bell_bearing_som"?7:4;
        if(a.step>deriveCurrentStep({})+500)score*=0.3;
        break;
    }
    a.score=score;
  });
  actions.sort(function(a,b){return b.score-a.score;});
  return actions;
}

function resolveStats(cls,template,targetLevel){
  var free=targetLevel-cls.level;
  var stats={};var offStats=["str","dex","int","fai","arc"];
  // Start from class base for all 8 stats
  ["vig","mnd","end","str","dex","int","fai","arc"].forEach(function(s){stats[s]=cls[s];});
  // Push offensive stats to template targets (spending free points)
  offStats.forEach(function(s){
    var need=Math.max(template.targets[s]-cls[s],0);
    if(need>0&&free>=need){stats[s]=template.targets[s];free-=need;}
    else if(need>0){stats[s]=cls[s]+free;free=0;}
  });
  // Spill remainder into primary stat, then secondary if primary caps at 99
  if(free>0){
    var sorted=offStats.slice().sort(function(a,b){return template.targets[b]-template.targets[a];});
    for(var si=0;si<sorted.length&&free>0;si++){
      var before=stats[sorted[si]];
      stats[sorted[si]]=Math.min(before+free,99);
      free-=(stats[sorted[si]]-before);
    }
  }
  return stats;
}

function filterArchPool(weapons,affPref,priStats,excludeDLC){
  return weapons.filter(function(wEnc){
    if(excludeDLC&&DLC_WEAPONS[wEnc.w])return false;
    if(wEnc.a===-1){
      if(!priStats.length)return true;
      var hasScaling=false;
      if(wEnc.as){wEnc.as.forEach(function(pair){if(priStats.indexOf(pair[0])>=0&&pair[1]>0)hasScaling=true;});}
      return hasScaling;
    }
    return affPref.indexOf(wEnc.a)>=0;
  });
}

function isBuildRelevant(itemScaling,archetype){if(!archetype)return true;var tmpl=STAT_TEMPLATES.find(function(t){return t.id===archetype});if(!tmpl)return true;var ps=tmpl.primaryStats;for(var i=0;i<itemScaling.length;i++){if(ps.indexOf(itemScaling[i])>=0)return true;}return false;}

function computeProgressionCurve(template,includeDLC,weaponList){
  var cls=WRETCH;
  var bossList=MANDATORY_BOSSES.base.slice();
  if(includeDLC)bossList=bossList.concat(MANDATORY_BOSSES.dlc);
  // Filter weapon pool by archetype affinity preference
  var affPref=template.affPref||[];
  var priStats=template.primaryStats||[];
  var baseCount=MANDATORY_BOSSES.base.length;
  var allWeapons=weaponList||ENG_DATA.reg.w;
  var baseArchPool=filterArchPool(allWeapons,affPref,priStats,true);
  var dlcArchPool=filterArchPool(allWeapons,affPref,priStats,false);
  // Detect caster archetype — needs catalyst (staff/seal) recommendation
  var isCaster=priStats.indexOf("int")>=0||priStats.indexOf("fai")>=0;
  var catalystType=priStats.indexOf("int")>=0?57:priStats.indexOf("fai")>=0?61:0;
  // Hybrids with both int+fai could use either; prioritize int (staff) for int_fth
  if(priStats.indexOf("int")>=0&&priStats.indexOf("fai")>=0)catalystType=57;
  var curve=[];
  for(var i=0;i<bossList.length;i++){
    var boss=bossList[i];
    var isDLC=i>=baseCount;
    var archPool=isDLC?dlcArchPool:baseArchPool;
    var baseStats=resolveStats(cls,template,boss.lvl);
    // Apply talisman stat bonuses before weapon ranking
    var talismanBonus=computeTalismanBonus(template.id);
    var stats=Object.assign({},baseStats);
    if(talismanBonus.statBonus){Object.keys(talismanBonus.statBonus).forEach(function(k){if(stats[k]!==undefined)stats[k]+=talismanBonus.statBonus[k];});}
    var gateState=deriveGateState({},boss.step);
    var rc=REGION_CAPS[boss.region]||{reg:0,smbr:0};
    var maxReg=Math.max(rc.reg,gateState.buyableRegMax);
    var maxSom=Math.max(rc.smbr,gateState.buyableSomMax);
    var synthGate=Object.assign({},gateState,{buyableRegMax:maxReg,buyableSomMax:maxSom});
    var w1h=bestWeaponForBoss(boss.name,stats,synthGate,boss.region,false,archPool);
    var w2h=bestWeaponForBoss(boss.name,stats,synthGate,boss.region,true,archPool);
    var best1h=w1h[0]||null;var best2h=w2h[0]||null;
    // Apply talisman melee damage multiplier
    if(best1h&&talismanBonus.meleeMult!==1){best1h=Object.assign({},best1h,{dmgPerHit:Math.floor(best1h.dmgPerHit*talismanBonus.meleeMult),hitsToKill:Math.ceil((best1h.bossHP||1)/Math.max(best1h.dmgPerHit*talismanBonus.meleeMult,1))});}
    if(best2h&&talismanBonus.meleeMult!==1){best2h=Object.assign({},best2h,{dmgPerHit:Math.floor(best2h.dmgPerHit*talismanBonus.meleeMult),hitsToKill:Math.ceil((best2h.bossHP||1)/Math.max(best2h.dmgPerHit*talismanBonus.meleeMult,1))});}
    var best=(best2h&&best1h)?(best2h.dmgPerHit>best1h.dmgPerHit?best2h:best1h):(best2h||best1h);
    var twoHanded=best&&best2h&&best===best2h;
    // Catalyst for caster archetypes
    var catalyst=null;var catalystList=[];
    if(isCaster&&catalystType){
      catalystList=bestCatalystAtCheckpoint(stats,synthGate,boss.region,catalystType,isDLC);
      catalyst=catalystList[0]||null;
    }
    var br=BOSS_READY[boss.name];
    var status=best?(best.hitsToKill<=(br?br.comf:30)?"READY":best.hitsToKill<=(br?br.strug:60)?"CHALLENGING":"UNDERPOWERED"):"NO_WEAPON";
    // Spell availability + DPS for casters
    var spells=isCaster?availableSpells(stats,catalystType===57?"sorcery":"incantation",boss.step):[];
    var bestSpell=null;var spellDmgList=[];
    if(isCaster&&catalyst&&spells.length){
      var engBoss=ENG_DATA.bosses[BOSS_ENG_MAP[boss.name]]||boss;
      spells.forEach(function(sp){
        if(sp.type==="Buff"||sp.type==="Heal")return;
        var sd=engSpellDmgVsBoss(catalyst.spellScaling,sp,engBoss);
        if(sd){var sDmg=Math.floor(sd.damage*talismanBonus.spellMult);var sDps=sd.castTime>0?Math.floor(sDmg/sd.castTime):sDmg;spellDmgList.push({name:sp.name,fp:sp.fp,type:sp.type,damage:sDmg,dps:sDps,fpEff:sDmg>0?(sp.fp/sDmg):999,castTime:sd.castTime,notes:sd.notes});}
      });
      spellDmgList.sort(function(a,b){return b.dps-a.dps;});
      bestSpell=spellDmgList[0]||null;
    }
    // Talisman loadout (optimal 4 per archetype, with damage applied above)
    var talismans=TALISMAN_LOADOUT[template.id]||bestTalismans(template);
    // Ashes of War
    var aows=bestAshOfWar(template,boss.step);
    // Weapon buffs
    var buffs=availableBuffs(template,stats,boss.step);
    // Poise info
    var engBossForPoise=ENG_DATA.bosses[BOSS_ENG_MAP[boss.name]]||null;
    var poiseInfo=engBossForPoise?getBossPoiseInfo(engBossForPoise):null;
    var weaponStagger=best?STAGGER_TIER[best.weaponType||0]||0:0;
    // Add weaponType to best if available
    if(best&&!best.weaponType){
      var bestEnc=(archPool||ENG_DATA.reg.w).find(function(w){return w.w===best.name&&(w.a===best.affinity||best.affinity===-1);});
      if(bestEnc)weaponStagger=STAGGER_TIER[bestEnc.t]||0;
    }
    curve.push({boss:boss.name,region:boss.region,level:boss.lvl,step:boss.step,
      stats:stats,affinities:gateState.affLabels,upgradeCap:{reg:maxReg,som:maxSom},
      weapon:best,weapon1h:best1h,weapon2h:best2h,twoHanded:twoHanded,
      catalyst:catalyst,catalystList:catalystList,isCaster:isCaster,casterLoadout:CASTER_LOADOUT[template.id]||null,
      spells:spells,spellDmgList:spellDmgList,bestSpell:bestSpell,talismans:talismans,
      aows:aows,buffs:buffs,talismanBonus:talismanBonus,poiseInfo:poiseInfo,staggerTier:weaponStagger,
      status:status,bossReady:br,top3_1h:w1h.slice(0,3),top3_2h:w2h.slice(0,3)});
  }
  return curve;
}

function bestCatalystAtCheckpoint(stats,gateState,regionName,catalystType,isDLC,weaponList){
  var rc=REGION_CAPS[regionName]||{reg:0,smbr:0};
  var maxSom=Math.max(rc.smbr,gateState.buyableSomMax);
  var engStats={str:stats.str||10,dex:stats.dex||10,int:stats.int||10,fai:stats.fai||10,arc:stats.arc||10};
  var results=[];
  (weaponList||ENG_DATA.reg.w).forEach(function(wEnc){
    if(wEnc.a!==-1)return; // catalysts are always unique
    if(wEnc.t!==catalystType)return;
    if(!isDLC&&DLC_WEAPONS[wEnc.w])return;
    if(!meetsRequirements(wEnc,engStats,false))return;
    var maxUp=(ENG_DATA.reg.rt[wEnc.ri]||[]).length-1;
    var upg=Math.min(maxSom,maxUp);
    var decoded=engDecodeWAtLevel(wEnc,upg);if(!decoded)return;
    var ar=engCalcAR(decoded,engStats,0,false);
    var scaling=ar.spellScaling[0]?Math.floor(ar.spellScaling[0]):0;
    if(scaling>0)results.push({name:wEnc.w,upgrade:upg,spellScaling:scaling,affinityName:"Unique"});
  });
  results.sort(function(a,b){return b.spellScaling-a.spellScaling;});
  return results.slice(0,5);
}

function getPlayerBossDmg(bossName,charState){
  if(!charState||!charState.loadout)return null;
  var weapon=charState.loadout.rh1;
  if(!weapon)return null;
  var bossIdx=BOSS_ENG_MAP[bossName];
  if(bossIdx===undefined)return null;
  var boss=ENG_DATA.bosses[bossIdx];
  if(!boss)return null;
  var wData=ENG_DATA.reg.w.find(function(w){return w.w===weapon;});
  if(!wData)return null;
  var decoded=engDecodeW(wData);
  if(!decoded)return null;
  var stats=charState.stats||{};
  var engStats={str:stats.str||10,dex:stats.dex||10,int:stats.int||10,fai:stats.fai||10,arc:stats.arc||10};
  var arResult=engCalcAR(decoded,engStats,decoded.maxUpgrade,false);
  if(!arResult)return null;
  var dmg=engDmgVsBoss(arResult,boss,wData.t);
  var totalAR=0;[0,1,2,3,4].forEach(function(dt){totalAR+=(arResult.attackPower[dt]||0);});
  return{hitsToKill:dmg.hitsToKill,dmgPerHit:dmg.total,totalAR:Math.floor(totalAR),bossHP:boss.hp,bossName:boss.n};
}

function deriveGateState(ci,atStep){
  var affinities=[],affLabels=[];
  var ownedWhetstones=[];
  for(var w=0;w<GATE_WHETSTONES.length;w++){
    var wObtained=atStep!==undefined?GATE_WHETSTONES[w].step<=atStep:!!ci["w_"+GATE_WHETSTONES[w].step];
    if(wObtained){
      ownedWhetstones.push(GATE_WHETSTONES[w]);
      for(var a=0;a<GATE_WHETSTONES[w].affinities.length;a++){
        if(affinities.indexOf(GATE_WHETSTONES[w].affinities[a])===-1){
          affinities.push(GATE_WHETSTONES[w].affinities[a]);
          affLabels.push(GATE_WHETSTONES[w].labels[a]);
        }
      }
    }
  }
  var buyableRegMax=0,buyableSomMax=0;
  var ownedBB=[];
  for(var b=0;b<GATE_BELL_BEARINGS.length;b++){
    var bObtained=atStep!==undefined?GATE_BELL_BEARINGS[b].step<=atStep:!!ci["w_"+GATE_BELL_BEARINGS[b].step];
    if(bObtained){
      ownedBB.push(GATE_BELL_BEARINGS[b]);
      if(GATE_BELL_BEARINGS[b].type==="regular"&&GATE_BELL_BEARINGS[b].maxReg>buyableRegMax) buyableRegMax=GATE_BELL_BEARINGS[b].maxReg;
      if(GATE_BELL_BEARINGS[b].type==="somber"&&GATE_BELL_BEARINGS[b].maxSmbr>buyableSomMax) buyableSomMax=GATE_BELL_BEARINGS[b].maxSmbr;
    }
  }
  var nextWhet=null,nextRegBB=null,nextSomBB=null;
  if(atStep===undefined){
    for(var w2=0;w2<GATE_WHETSTONES.length;w2++){if(!ci["w_"+GATE_WHETSTONES[w2].step]){nextWhet=GATE_WHETSTONES[w2];break}}
    for(var b2=0;b2<GATE_BELL_BEARINGS.length;b2++){if(!ci["w_"+GATE_BELL_BEARINGS[b2].step]){if(GATE_BELL_BEARINGS[b2].type==="regular"&&!nextRegBB) nextRegBB=GATE_BELL_BEARINGS[b2];if(GATE_BELL_BEARINGS[b2].type==="somber"&&!nextSomBB) nextSomBB=GATE_BELL_BEARINGS[b2];}}
  }
  return{affinities:affinities,affLabels:affLabels,ownedWhetstones:ownedWhetstones,ownedBB:ownedBB,buyableRegMax:buyableRegMax,buyableSomMax:buyableSomMax,nextWhet:nextWhet,nextRegBB:nextRegBB,nextSomBB:nextSomBB}
}

function getNextMandatoryBoss(ci,includeDLC){
  var bossList=MANDATORY_BOSSES.base.slice();
  if(includeDLC)bossList=bossList.concat(MANDATORY_BOSSES.dlc);
  for(var i=0;i<bossList.length;i++){
    var b=bossList[i];
    if(!ci["boss_"+b.name]&&!ci["b_"+b.name]){
      var engBoss=ENG_DATA.bosses[b.idx]||null;
      return{name:b.name,region:b.region,step:b.step,lvl:b.lvl,idx:b.idx,engBoss:engBoss,ready:BOSS_READY[b.name]||null};
    }
  }
  return null;
}

function resolveTacticalNeeds(bossName,ci){
  var results=[];
  for(var i=0;i<TACTICAL_NEEDS.length;i++){
    var tn=TACTICAL_NEEDS[i];
    if(tn.bosses.indexOf(bossName)===-1) continue;
    var obtained=[],available=[];
    for(var p=0;p<tn.providers.length;p++){
      var prov=tn.providers[p];
      if(prov.step&&ci["w_"+prov.step]){obtained.push(prov)}
      else{available.push(prov)}
    }
    results.push({need:tn.need,desc:tn.desc,obtained:obtained,available:available,satisfied:obtained.length>0})
  }
  return results
}

function getEnemyResistWarning(step,charState){
  var warnings=[];
  for(var i=0;i<ENEMY_RESIST.length;i++){
    var er=ENEMY_RESIST[i];
    var inZone=false;
    for(var j=0;j<er.steps.length;j++){
      if(step>=er.steps[j][0]&&step<=er.steps[j][1]){inZone=true;break;}
    }
    if(!inZone)continue;
    // Check player's equipped weapon damage subtype
    var playerResisted=false;var playerSubtype=null;
    if(charState&&charState.loadout){
      var slots=["rh1","rh2"];
      for(var s=0;s<slots.length;s++){
        var wSlot=charState.loadout[slots[s]];
        if(!wSlot||!wSlot.name)continue;
        var wEnc=ENG_DATA.reg.w.find(function(w){return w.w===wSlot.name&&(wSlot.affinity===-1||w.a===wSlot.affinity);});
        if(!wEnc)continue;
        playerSubtype=PHYS_SUBTYPE[wEnc.t]||"standard";
        if(er.resists.indexOf(playerSubtype)>=0)playerResisted=true;
      }
    }
    // Find a strike weapon the player can use
    var strikeRec=null;
    if(charState&&charState.stats){
      var stats=charState.stats;
      var bestAR=0;
      ENG_DATA.reg.w.filter(function(w){return PHYS_SUBTYPE[w.t]==="strike"&&w.a<=0;}).forEach(function(w){
        if(!meetsRequirements(w,stats,false))return;
        var dec=engDecodeWAtLevel(w,0);if(!dec)return;
        var ar=engCalcAR(dec,stats,0,false);
        var total=0;[0,1,2,3,4].forEach(function(dt){total+=(ar.attackPower[dt]||0);});
        if(total>bestAR){bestAR=total;strikeRec=w.w;}
      });
    }
    warnings.push({enemy:er.enemy,resists:er.resists,effective:er.effective,note:er.note,playerResisted:playerResisted,playerSubtype:playerSubtype,strikeRec:strikeRec});
  }
  return warnings;
}

function endingAvailability(ci,qp){
  var ED=ENDING_DATA;
  var malikethDone=!!ci["w_"+ED.maliketh];
  var frenziedAccepted=ED.frenziedAccept.some(function(s){return!!ci["w_"+s];})||(qp[ED.hyettaQuest]>=ED.hyettaDone);
  var frenziedCured=!!ci["w_"+ED.frenziedCure];
  var frenziedLock=frenziedAccepted&&!frenziedCured;

  // Seedbed curse tracking
  var seedTotal=0,seedLeyndellMissed=0,seedDetail=[];
  ED.seedbedSteps.forEach(function(sc){
    var got=!!ci["w_"+sc.s];
    if(got)seedTotal++;
    seedDetail.push({loc:sc.loc,obtained:got,atRisk:sc.leyndell&&!got&&!malikethDone,lost:sc.leyndell&&!got&&malikethDone});
  });
  var seedAvailableAfterBurn=seedTotal+ED.seedbedSteps.filter(function(sc){return!sc.leyndell&&!ci["w_"+sc.s];}).length;

  var results=[];

  // Age of Fracture — always available
  results.push({id:"end_elden_lord",name:"Age of Fracture",status:"available",detail:"Default ending — always available.",action:null});

  // Age of the Stars
  var ranniProg=qp[ED.ranniQuest]||0;
  if(ranniProg>=ED.ranniDone){
    results.push({id:"end_age_stars",name:"Age of the Stars",status:"available",detail:"Ranni's questline complete.",action:null});
  }else{
    results.push({id:"end_age_stars",name:"Age of the Stars",status:"at_risk",detail:"Ranni's questline: step "+ranniProg+" of "+ED.ranniDone+".",action:"Complete Ranni's questline before final boss."});
  }

  // Lord of Frenzied Flame
  if(frenziedAccepted){
    results.push({id:"end_frenzied",name:"Lord of Frenzied Flame",status:"available",detail:frenziedCured?"Accepted then cured — can still choose this ending.":"Three Fingers accepted. This is your current locked ending.",action:frenziedCured?null:"Use Miquella's Needle at Placidusax arena to unlock other endings."});
  }else{
    results.push({id:"end_frenzied",name:"Lord of Frenzied Flame",status:"at_risk",detail:"Must reach Three Fingers in Subterranean Shunning-Grounds.",action:"Strip armor and enter door past Mohg the Omen."});
  }

  // Age of Duskborn
  var hasDuskRune=!!ci["w_"+ED.duskbornRune];
  if(hasDuskRune){
    results.push({id:"end_duskborn",name:"Age of Duskborn",status:"available",detail:"Mending Rune of the Death-Prince obtained.",action:null});
  }else{
    results.push({id:"end_duskborn",name:"Age of Duskborn",status:"at_risk",detail:"Fia's questline incomplete.",action:"Complete Fia's quest → defeat Lichdragon Fortissax → collect Mending Rune."});
  }

  // Age of Order
  var hasOrderRune=!!ci["w_"+ED.orderRune];
  var regressionDone=!!ci["w_"+ED.regressionPuzzle];
  if(hasOrderRune){
    results.push({id:"end_order",name:"Age of Order",status:"available",detail:"Mending Rune of Perfect Order obtained.",action:null});
  }else if(malikethDone&&!regressionDone){
    results.push({id:"end_order",name:"Age of Order",status:"locked",detail:"Law of Regression puzzle missed in Royal Capital.",action:"Cannot complete Goldmask quest — Leyndell is now Capital of Ash."});
  }else if(!regressionDone){
    results.push({id:"end_order",name:"Age of Order",status:"at_risk",detail:"Law of Regression puzzle not yet completed.",action:"Cast Law of Regression at Radagon's Statue in Leyndell (requires 37 INT). Must do before defeating Maliketh."});
  }else{
    results.push({id:"end_order",name:"Age of Order",status:"at_risk",detail:"Regression puzzle done. Complete Goldmask's questline for the rune.",action:"Find Goldmask in Mountaintops → Capital of Ash."});
  }

  // Blessing of Despair
  var gaveDungPotion=!!ci["w_"+ED.dungEaterPotion];
  var hasFellRune=!!ci["w_"+ED.despairRune];
  if(gaveDungPotion){
    results.push({id:"end_despair",name:"Blessing of Despair",status:"locked",detail:"Seluvis' Potion given to Dung Eater.",action:"Mending Rune of the Fell Curse unavailable this playthrough.",seedDetail:seedDetail});
  }else if(hasFellRune){
    results.push({id:"end_despair",name:"Blessing of Despair",status:"available",detail:"Mending Rune of the Fell Curse obtained.",action:null,seedDetail:seedDetail});
  }else if(seedTotal>=5){
    results.push({id:"end_despair",name:"Blessing of Despair",status:"at_risk",detail:seedTotal+" of 5 Seedbed Curses collected.",action:"Deliver curses to Dung Eater in Subterranean Shunning-Grounds.",seedDetail:seedDetail});
  }else if(malikethDone&&seedAvailableAfterBurn<5){
    results.push({id:"end_despair",name:"Blessing of Despair",status:"locked",detail:"Only "+seedAvailableAfterBurn+" Seedbed Curses obtainable (need 5). Leyndell curses lost.",action:"Not enough curses remaining this playthrough.",seedDetail:seedDetail});
  }else{
    var leyndellAtRisk=seedDetail.filter(function(d){return d.atRisk;}).length;
    results.push({id:"end_despair",name:"Blessing of Despair",status:"at_risk",detail:seedTotal+" of 5 Seedbed Curses collected."+(leyndellAtRisk>0?" "+leyndellAtRisk+" in Leyndell at risk if Erdtree burns.":""),action:"Collect remaining curses."+(leyndellAtRisk>0?" Leyndell curses lost after Maliketh.":""),seedDetail:seedDetail});
  }

  // Apply Frenzied Flame lock override
  if(frenziedLock){
    results.forEach(function(r){
      if(r.id!=="end_frenzied"&&r.status==="available"){
        r.status="locked";r.detail="Frenzied Flame accepted — locks all other endings.";r.action="Use Miquella's Needle at Dragonlord Placidusax arena to reverse.";
      }
    });
  }

  return results;
}

function _dsLookup(t,keys,v){if(v<=keys[0])return t[keys[0]];if(v>=keys[keys.length-1])return t[keys[keys.length-1]];for(var i=0;i<keys.length-1;i++){if(v>=keys[i]&&v<=keys[i+1]){var r=(v-keys[i])/(keys[i+1]-keys[i]);return Math.round(t[keys[i]]+(t[keys[i+1]]-t[keys[i]])*r);}}return t[keys[keys.length-1]];}

function evalCCGraph(graph){var arr=[];for(var i=1;i<graph.length;i++){var prev=graph[i-1],stage=graph[i];var mn=i===1?1:prev.maxVal+1,mx=i===graph.length-1?148:stage.maxVal;for(var a=mn;a<=mx;a++){if(!arr[a]){var r=Math.max(0,Math.min(1,(a-prev.maxVal)/(stage.maxVal-prev.maxVal)));if(prev.adjPt>0)r=Math.pow(r,prev.adjPt);else if(prev.adjPt<0)r=1-Math.pow(1-r,-prev.adjPt);arr[a]=prev.maxGrowVal+(stage.maxGrowVal-prev.maxGrowVal)*r;}}}return arr;}

